using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateSeededContext();
        _controller = new StudentsController(_context);
        // Setup minimal HTTP context for ViewBag/TempData
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            _controller.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithStudents()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count); // 3 seeded students
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByNameDesc_ReturnsDescendingOrder()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Descending: Barzdukas, Alonso, Alexander
        Assert.AreEqual("Barzdukas", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByDate_ReturnsDateAscending()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2010 < 2012 — Alexander first
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByDateDesc_ReturnsDateDescending()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2012 students first (Alonso or Barzdukas alphabetically by queryable ordering)
        Assert.IsTrue(model[0].EnrollmentDate >= model[model.Count - 1].EnrollmentDate);
    }

    [TestMethod]
    public void Index_SearchString_ResetsPageTo1()
    {
        // Act
        var result = _controller.Index(null, null, "A", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_CurrentFilter_UsedWhenSearchStringNull()
    {
        // Act
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

