    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
    {
        // Arrange
        var initialCount = _context.Courses.Count();

        // Act
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Courses.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_CourseWithImagePath_DeletesImageFile()
    {
        // Arrange - set up course with an image
        var course = _context.Courses.Find(1050)!;
        var relativePath = "/Uploads/TeachingMaterials/test_image.jpg";
        course.TeachingMaterialImagePath = relativePath;
        _context.SaveChanges();

        // Create the actual file
        var fullPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials", "test_image.jpg");
        Directory.CreateDirectory(Path.GetDirectoryName(fullPath)!);
        File.WriteAllText(fullPath, "fake image");

        // Act
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(File.Exists(fullPath));
    }

    private static IFormFile CreateFormFile(string fileName, string content)
    {
        var bytes = Encoding.UTF8.GetBytes(content);
        var stream = new MemoryStream(bytes);
        return new FormFile(stream, 0, bytes.Length, "teachingMaterialImage", fileName);
    }
}

