        using var context1 = TestDbContextHelper.CreateContext(dbName);
        DbInitializer.Initialize(context1);
        var studentCount = context1.Students.Count();

        // Act - call Initialize again with same DB
        using var context2 = TestDbContextHelper.CreateContext(dbName);
