+
+[TestClass]
+public sealed class PaginatedListTests
+{
+    [TestMethod]
+    public void Constructor_SetsPageIndexAndTotalPages()
+    {
+        // Arrange
+        var items = new List<string> { "a", "b", "c" };
+
+        // Act
+        var result = new PaginatedList<string>(items, 10, 2, 3);
+
+        // Assert
+        Assert.AreEqual(2, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
+    }
+
+    [TestMethod]
+    public void Constructor_ContainsAllItems()
+    {
+        // Arrange
+        var items = new List<int> { 1, 2, 3 };
+
+        // Act
+        var result = new PaginatedList<int>(items, 5, 1, 3);
+
+        // Assert
+        Assert.AreEqual(3, result.Count);
+        Assert.AreEqual(1, result[0]);
+        Assert.AreEqual(2, result[1]);
+        Assert.AreEqual(3, result[2]);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_FirstPage_ReturnsFalse()
+    {
+        var result = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3);
+        Assert.IsFalse(result.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_SecondPage_ReturnsTrue()
+    {
+        var result = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3);
+        Assert.IsTrue(result.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_LastPage_ReturnsFalse()
+    {
+        // 5 items, page size 3 → 2 pages total, on page 2
+        var result = new PaginatedList<int>(new List<int> { 4, 5 }, 5, 2, 3);
+        Assert.IsFalse(result.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_FirstPage_ReturnsTrue()
+    {
+        var result = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 5, 1, 3);
+        Assert.IsTrue(result.HasNextPage);
+    }
+
+    [TestMethod]
+    public void Create_ReturnsCorrectPage()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 20).AsQueryable();
+
+        // Act
+        var page1 = PaginatedList<int>.Create(source, 1, 5);
+        var page2 = PaginatedList<int>.Create(source, 2, 5);
+
+        // Assert
+        Assert.AreEqual(5, page1.Count);
+        Assert.AreEqual(1, page1[0]);
+        Assert.AreEqual(5, page1[4]);
+
+        Assert.AreEqual(5, page2.Count);
+        Assert.AreEqual(6, page2[0]);
+        Assert.AreEqual(10, page2[4]);
+    }
+
+    [TestMethod]
+    public void Create_LastPage_HasPartialItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 7).AsQueryable();
+
+        // Act
+        var page3 = PaginatedList<int>.Create(source, 3, 3);
+
+        // Assert
+        Assert.AreEqual(1, page3.Count); // only item 7
+        Assert.AreEqual(7, page3[0]);
+    }
+
+    [TestMethod]
+    public void TotalPages_CalculatedCorrectly()
+    {
+        var source = Enumerable.Range(1, 7).AsQueryable();
+        var result = PaginatedList<int>.Create(source, 1, 3);
+        Assert.AreEqual(3, result.TotalPages); // ceil(7/3) = 3
+    }
+
+    [TestMethod]
+    [DataRow(1, 1, false, false)]   // 1 item, 1 per page -> page 1 of 1
+    [DataRow(10, 5, false, true)]   // 10 items, 5 per page, on page 1 -> has next
+    [DataRow(10, 10, false, false)] // 10 items, 10 per page -> 1 page total
+    public void Create_PaginationFlags_CorrectOnFirstPage(int totalItems, int pageSize, bool expectedPrev, bool expectedNext)
+    {
+        // Arrange
+        var source = Enumerable.Range(1, totalItems).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 1, pageSize);
+
+        // Assert
+        Assert.AreEqual(expectedPrev, result.HasPreviousPage);
+        Assert.AreEqual(expectedNext, result.HasNextPage);
+    }
+}
