[TestMethod]
public void Index_WithCourseId_PopulatesEnrollments()
{
    // Arrange - create a clean context with a simpler setup to avoid InMemory Include quirks
    var dbName = System.Guid.NewGuid().ToString();
    using var ctx = TestDbContextHelper.CreateContext(dbName);

    var dept = new Department { DepartmentID = 1, Name = "Eng", Budget = 1000m, StartDate = new DateTime(2020, 1, 1) };
    ctx.Departments.Add(dept);

    var student = new Student { ID = 1, LastName = "Test", FirstMidName = "Student", EnrollmentDate = new DateTime(2020, 1, 1), Enrollments = new List<Enrollment>() };
    ctx.Students.Add(student);

    var course = new Course { CourseID = 100, Title = "TestCourse", Credits = 3, DepartmentID = 1, CourseAssignments = new List<CourseAssignment>(), Enrollments = new List<Enrollment>() };
    ctx.Courses.Add(course);

    var instructor = new Instructor { ID = 1, LastName = "Prof", FirstMidName = "Test", HireDate = new DateTime(2020, 1, 1), CourseAssignments = new List<CourseAssignment>() };
    ctx.Instructors.Add(instructor);
    ctx.SaveChanges();

    var ca = new CourseAssignment { CourseID = 100, InstructorID = 1 };
    ctx.CourseAssignments.Add(ca);

    var enrollment = new Enrollment { CourseID = 100, StudentID = 1, Grade = Grade.A };
    ctx.Enrollments.Add(enrollment);
    ctx.SaveChanges();

    using var controller = new InstructorsController(ctx);

    // Act
    var result = controller.Index(1, 100) as ViewResult;

    // Assert
    Assert.IsNotNull(result);
    var model = result.Model as InstructorIndexData;
    Assert.IsNotNull(model);
    Assert.IsNotNull(model.Enrollments);
    Assert.IsTrue(model.Enrollments.Any());
}

